const items = $input.all();
if (items.length === 0) {
  return [{ json: { _empty: true } }];
}
return items;

const client = $('Loop Over Clients').first().json;
const isNew  = client.lead_sheet_tab === 'Leads';

// Derive column names from field_map for new format
let emailCol, phoneCol, nameCol, firstNameCol, lastNameCol, serviceCol;
if (isNew && client.intake_config && client.intake_config.field_map) {
  const fm  = client.intake_config.field_map;
  const inv = {};
  for (const [k, v] of Object.entries(fm)) inv[v] = k;
  emailCol     = inv['email']            || 'Email';
  phoneCol     = inv['phone']            || 'Phone';
  firstNameCol = inv['first_name']       || null;
  lastNameCol  = inv['last_name']        || null;
  nameCol      = inv['name']             || null;
  serviceCol   = inv['service_interest'] || inv['service'] || null;
} else {
  emailCol   = 'Lead Email';
  phoneCol   = 'Lead Phone';
  nameCol    = 'Lead Name';
  serviceCol = 'Service';
}

// Build sent-contact set from Review Status
const reviewRows = $('Read Review Status Tab').all();
const sentCol    = isNew ? 'Review Sent'  : 'Review Email Sent';
const sentIdCol  = isNew ? 'Phone'        : 'Source Ref';

const sentContacts = new Set(
  reviewRows
    .filter(item => {
      const sent = item.json[sentCol];
      return sent === true || String(sent).toUpperCase().trim() === 'TRUE';
    })
    .map(item => String(item.json[sentIdCol] || '').toLowerCase().trim())
    .filter(Boolean)
);

// Filter Leads rows
const leadRows = $('Read Client Lead Sheet').all();
const qualifying = leadRows.filter(item => {
  const r      = item.json;
  const status = String(r['Status'] || '').trim();
  const email  = String(r[emailCol] || '').toLowerCase().trim();
  const phone  = String(r[phoneCol] || '').trim();
  const key    = isNew ? phone.toLowerCase() : (email || phone.toLowerCase());
  return status === 'Completed' && key && !sentContacts.has(key);
}).map(item => {
  const r     = item.json;
  const email = String(r[emailCol] || '').toLowerCase().trim();
  const phone = String(r[phoneCol] || '').trim();

  let lead_name;
  if (nameCol && r[nameCol]) {
    lead_name = String(r[nameCol]).trim();
  } else if (firstNameCol) {
    lead_name = [String(r[firstNameCol] || ''), lastNameCol ? String(r[lastNameCol] || '') : ''].join(' ').trim();
  } else {
    lead_name = '';
  }

  const source_ref = isNew ? phone : (email || phone);

  return { json: {
    client_slug:    client.client_slug,
    lead_name,
    lead_email:     email,
    service:        serviceCol ? String(r[serviceCol] || '') : '',
    business_name:  String(r['Business Name'] || ''),
    address:        String(r['Address'] || ''),
    source_type:    'sheet',
    source_ref,
    lead_sheet_id:  client.lead_sheet_id,
    lead_sheet_tab: client.lead_sheet_tab
  }};
});

if (qualifying.length === 0) {
  return [{ json: { _skip: true } }];
}
return qualifying;
